// Find tasks that are open and (overdue OR due today/tomorrow)
const today = new Date(); today.setHours(0,0,0,0);
const tomorrow = new Date(today); tomorrow.setDate(tomorrow.getDate()+1);
const toDate = (s) => { if(!s) return null; const d = new Date(s); d.setHours(0,0,0,0); return d; };

const items = $input.all();
const alerts = [];
for (const it of items) {
  const t = it.json;
  if (t.status === 'done' || t.status === 'deleted') continue;
  const due = toDate(t.due);
  if (!due) continue;
  let kind = null;
  if (due < today) kind = 'overdue';
  else if (due.getTime() === today.getTime()) kind = 'today';
  else if (due.getTime() === tomorrow.getTime()) kind = 'tomorrow';
  if (kind) alerts.push({ json: { ...t, alertKind: kind } });
}
return alerts;

